CODE_EXAMPLE:
interface EmailSender { void send(Email email); }

class ReportService {
    private final EmailSender sender;
    // Dependency injected via constructor
    public ReportService(EmailSender sender) { this.sender = sender; }
    public void sendReport(Report report) { sender.send(report.toEmail()); }
}

// Wiring happens outside:
// new ReportService(new SmtpEmailSender(config))

UNIT_TEST_EXAMPLE:
@Test
public void sendReport_delegatesToEmailSender() {
    EmailSender mockSender = mock(EmailSender.class);
    ReportService service = new ReportService(mockSender);
    Report report = new Report("Q1 Results");
    service.sendReport(report);
    verify(mockSender).send(report.toEmail());
}
